const m0001 = "-- クライアントアプリD1（設計書§8）。配備＝1組織なのでテナント分割なし。\n-- 数値・科目・日付・口座区分は平文（集計のため）。PII・摘要はアプリ層で暗号化（§10）。\n\n-- 会計コア（§8.1） --------------------------------------------------------\nCREATE TABLE IF NOT EXISTS fiscal_periods (\n  id TEXT PRIMARY KEY,\n  name TEXT NOT NULL,\n  start_date TEXT NOT NULL,\n  end_date TEXT NOT NULL,\n  status TEXT NOT NULL DEFAULT 'open'      -- open / closed\n);\n\nCREATE TABLE IF NOT EXISTS wallets (\n  id TEXT PRIMARY KEY,\n  name TEXT NOT NULL,\n  type TEXT NOT NULL,                        -- cash / bank\n  opening_balance INTEGER NOT NULL DEFAULT 0,\n  sort_order INTEGER NOT NULL DEFAULT 0\n);\n\nCREATE TABLE IF NOT EXISTS categories (\n  id TEXT PRIMARY KEY,\n  name TEXT NOT NULL,\n  kind TEXT NOT NULL,                        -- income / expense\n  parent_id TEXT,\n  sort_order INTEGER NOT NULL DEFAULT 0\n);\n\nCREATE TABLE IF NOT EXISTS budgets (\n  id TEXT PRIMARY KEY,\n  fiscal_period_id TEXT NOT NULL,\n  category_id TEXT NOT NULL,\n  amount INTEGER NOT NULL\n);\n\nCREATE TABLE IF NOT EXISTS transactions (\n  id TEXT PRIMARY KEY,\n  fiscal_period_id TEXT NOT NULL,\n  date TEXT NOT NULL,\n  wallet_id TEXT NOT NULL,\n  kind TEXT NOT NULL,                        -- income / expense / transfer\n  category_id TEXT,\n  amount INTEGER NOT NULL,                    -- 円・整数\n  description TEXT,                           -- 摘要（△暗号化推奨）\n  counter_wallet_id TEXT,                     -- 振替先\n  created_by TEXT,                            -- users.id\n  receipt_ref TEXT,                           -- R2参照／個人領収書ID\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL,\n  deleted_at INTEGER                          -- ソフトデリート（§12）\n);\nCREATE INDEX IF NOT EXISTS idx_tx_period ON transactions (fiscal_period_id, date);\nCREATE INDEX IF NOT EXISTS idx_tx_wallet ON transactions (wallet_id, date);\nCREATE INDEX IF NOT EXISTS idx_tx_category ON transactions (category_id);\n\n-- マルチユーザー（§8.2） --------------------------------------------------\nCREATE TABLE IF NOT EXISTS users (\n  id TEXT PRIMARY KEY,\n  display_name TEXT,                          -- 暗号化\n  role TEXT NOT NULL DEFAULT 'member',        -- admin / accounting / clerical / other / member\n  status TEXT NOT NULL DEFAULT 'invited',     -- invited / pending / active / disabled\n  created_at INTEGER NOT NULL\n);\n\nCREATE TABLE IF NOT EXISTS identities (\n  id TEXT PRIMARY KEY,\n  user_id TEXT NOT NULL,\n  type TEXT NOT NULL,                          -- line / discord / local / google\n  external_id TEXT,                            -- LINE userId / Discord id / Google sub\n  password_hash TEXT,                          -- local時\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_identities_ext ON identities (type, external_id);\n\nCREATE TABLE IF NOT EXISTS invites (\n  id TEXT PRIMARY KEY,\n  code TEXT NOT NULL,\n  issued_by TEXT,\n  default_role TEXT NOT NULL DEFAULT 'member',\n  expires_at INTEGER NOT NULL,\n  max_uses INTEGER NOT NULL DEFAULT 1,\n  used_count INTEGER NOT NULL DEFAULT 0,\n  status TEXT NOT NULL DEFAULT 'active'        -- active / revoked\n);\nCREATE INDEX IF NOT EXISTS idx_invites_code ON invites (code);\n\nCREATE TABLE IF NOT EXISTS knowledge (\n  id TEXT PRIMARY KEY,\n  title TEXT,\n  body TEXT,\n  file_ref TEXT,\n  tags TEXT,\n  created_by TEXT,\n  created_at INTEGER NOT NULL\n);\n\nCREATE TABLE IF NOT EXISTS audit_log (\n  id TEXT PRIMARY KEY,\n  actor TEXT NOT NULL,                         -- user.id または 'org'\n  action TEXT NOT NULL,\n  target TEXT,\n  timestamp INTEGER NOT NULL\n);\n\nCREATE TABLE IF NOT EXISTS personal_items (\n  id TEXT PRIMARY KEY,\n  owner_user_id TEXT NOT NULL,\n  type TEXT NOT NULL,                          -- receipt / memo / task / schedule\n  title TEXT,\n  body TEXT,\n  amount INTEGER,\n  date TEXT,\n  due_at INTEGER,\n  status TEXT,\n  share_scope TEXT NOT NULL DEFAULT 'personal',-- personal / org\n  review_status TEXT NOT NULL DEFAULT 'none',  -- none / pending / approved / rejected\n  reviewed_by TEXT,\n  reviewed_at INTEGER,\n  reject_reason TEXT,\n  receipt_ref TEXT,\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_personal_owner ON personal_items (owner_user_id);\nCREATE INDEX IF NOT EXISTS idx_personal_review ON personal_items (review_status);\n";
const m0002 = "-- P4：ファイル・予定。議事録/ナレッジは knowledge を流用（tags で区別）。\n\nCREATE TABLE IF NOT EXISTS files (\n  id TEXT PRIMARY KEY,\n  name TEXT NOT NULL,            -- ファイル名（PIIを入れない運用・§10.2）\n  size INTEGER NOT NULL,\n  mime TEXT,\n  ref TEXT NOT NULL,             -- r2:<key> / kv:<key>\n  created_by TEXT,\n  created_at INTEGER NOT NULL,\n  deleted_at INTEGER             -- ソフトデリート（§12）\n);\nCREATE INDEX IF NOT EXISTS idx_files_live ON files (deleted_at, created_at);\n\nCREATE TABLE IF NOT EXISTS schedules (\n  id TEXT PRIMARY KEY,\n  title TEXT NOT NULL,\n  start_at TEXT NOT NULL,        -- ISO日時\n  end_at TEXT,\n  body TEXT,                     -- 詳細（△暗号化推奨だがPhase1は平文）\n  created_by TEXT,\n  created_at INTEGER NOT NULL,\n  deleted_at INTEGER\n);\nCREATE INDEX IF NOT EXISTS idx_sched_live ON schedules (deleted_at, start_at);\n\n-- 議事録/ナレッジ用に knowledge へソフトデリート列を追加（既存テーブル）。\nALTER TABLE knowledge ADD COLUMN deleted_at INTEGER;\n";
const m0003 = "-- P6エージェント：リマインダー（LINEへ通知）。Astro単一Workerはネイティブcron非対応のため、\n-- /api/cron/drain（外部スケジューラ or 手動）＋メッセージ受信時の遅延配信で実現。\nCREATE TABLE IF NOT EXISTS reminders (\n  id TEXT PRIMARY KEY,\n  owner TEXT NOT NULL,          -- line:<userId> 等\n  content TEXT NOT NULL,\n  remind_at INTEGER NOT NULL,   -- epoch秒\n  done INTEGER NOT NULL DEFAULT 0,\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_reminders_due ON reminders (done, remind_at);\n";
const m0004 = "-- P6エージェント：大PDF/ファイルの要約ジョブ（Files API＋drainステップ）。\nCREATE TABLE IF NOT EXISTS summary_jobs (\n  id TEXT PRIMARY KEY,\n  owner TEXT NOT NULL,           -- line:<userId> 等\n  name TEXT,                     -- ファイル名\n  file_id TEXT NOT NULL,         -- files.id（KV/R2に保管した本体）\n  status TEXT NOT NULL DEFAULT 'pending', -- pending / done / error\n  result TEXT,                   -- 要約結果（knowledge にも保存）\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_sumjobs_status ON summary_jobs (status, created_at);\n";
const m0005 = "-- 高度なオプション：ユーザー追加の Agent Skills（SKILL.md駆動）。\n-- mode=instruction（通常LLM費）／code（Anthropic code execution＝従量課金・高度なオプション）。\nCREATE TABLE IF NOT EXISTS skills (\n  id TEXT PRIMARY KEY,\n  name TEXT NOT NULL,            -- 呼び出し名（例：議事録フォーマット, 請求書生成）\n  description TEXT,\n  skill_md TEXT NOT NULL,        -- SKILL.md（手順・テンプレ）\n  mode TEXT NOT NULL DEFAULT 'instruction', -- instruction / code\n  enabled INTEGER NOT NULL DEFAULT 0,        -- 管理者がレビューして有効化\n  created_by TEXT,\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_skills_enabled ON skills (enabled);\n";
const m0006 = "-- 高度なオプション：任意API（能力レジストリ §5-2b の api 種別）。BYOK・暗号化保存。\nCREATE TABLE IF NOT EXISTS capabilities (\n  id TEXT PRIMARY KEY,\n  capability TEXT NOT NULL,      -- image_gen / tts / video_gen / embed / custom\n  provider TEXT,                 -- openai / stability / elevenlabs / 任意\n  endpoint TEXT,                 -- カスタム時のURL\n  model TEXT,\n  api_key TEXT,                  -- AES-GCM暗号化（MASTER_KEY）\n  enabled INTEGER NOT NULL DEFAULT 0,\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_cap_enabled ON capabilities (enabled);\n\n-- 診断・エラーログ（§7.1 診断・サポート／§13.3）。CF制限などの障害をUIに表示する。\nCREATE TABLE IF NOT EXISTS diagnostics (\n  id TEXT PRIMARY KEY,\n  level TEXT NOT NULL,           -- error / warn / info\n  category TEXT NOT NULL,        -- limit（CF制限）/ ai / storage / other\n  message TEXT NOT NULL,\n  context TEXT,\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_diag_time ON diagnostics (created_at);\n";
const m0007 = "-- 動画生成は非同期：作成→推定時間後にステータス確認→完了でDL。\nCREATE TABLE IF NOT EXISTS video_jobs (\n  id TEXT PRIMARY KEY,\n  owner TEXT NOT NULL,          -- line:<userId> 等\n  cap_id TEXT NOT NULL,         -- capabilities.id（プロバイダ/キー解決用）\n  job_id TEXT,\n  status_url TEXT,\n  prompt TEXT,\n  status TEXT NOT NULL DEFAULT 'pending', -- pending / done / error\n  file_id TEXT,                 -- 完成動画の files.id\n  eta INTEGER NOT NULL,         -- 次に確認する目安時刻(epoch秒)\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_videojobs ON video_jobs (status, eta);\n";
const m0008 = "-- API使用量（日次・プロバイダ別カウント）。AI機能・各APIの利用回数を記録（§使用量画面）。\nCREATE TABLE IF NOT EXISTS api_usage (\n  provider TEXT NOT NULL,   -- gemini / claude / web_search / image_gen / tts / video_gen / custom\n  day TEXT NOT NULL,        -- YYYY-MM-DD（UTC）\n  count INTEGER NOT NULL DEFAULT 0,\n  PRIMARY KEY (provider, day)\n);\n";
const m0009 = "-- Googleドライブ連携：ドライブ内ファイルのメタ情報同期＋バックアップ記録。\nCREATE TABLE IF NOT EXISTS drive_files (\n  id TEXT PRIMARY KEY,        -- Drive file id\n  name TEXT NOT NULL,\n  mime TEXT,\n  size INTEGER,\n  modified TEXT,              -- ISO（modifiedTime）\n  parents TEXT,              -- JSON配列文字列\n  synced_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_drive_files_name ON drive_files (name);\n\n-- KV/R2 → Drive バックアップ済みファイルの記録（重複アップロード防止）。\nCREATE TABLE IF NOT EXISTS drive_backup_log (\n  file_id TEXT PRIMARY KEY,   -- files.id（クライアント側）\n  drive_id TEXT,              -- アップロード先 Drive file id\n  at INTEGER NOT NULL\n);\n";
const m0010 = "-- 会員管理（会費を払う団体会員）。組織メンバー(users)・名簿(knowledge)とは別概念。\nCREATE TABLE IF NOT EXISTS membership (\n  id TEXT PRIMARY KEY,\n  name TEXT NOT NULL,\n  contact TEXT,                          -- 連絡先（電話/メール等）\n  fee_status TEXT NOT NULL DEFAULT 'unpaid', -- paid / unpaid / exempt / withdrawn\n  paid_at TEXT,                          -- 支払い日時（ISO/任意文字列）\n  status_changed_at INTEGER,             -- ステータス変更日時（epoch秒）\n  extra TEXT,                            -- 任意項目（JSON文字列）\n  stripe_customer TEXT,                  -- Stripe連携（要件B）用の顧客ID（任意）\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_membership_name ON membership (name);\nCREATE INDEX IF NOT EXISTS idx_membership_fee ON membership (fee_status);\n";
const m0011 = "-- HP/LP 公開機構（Pro以上）。サブパス公開（/site・/lp/<slug>）。slug=home がトップ。\nCREATE TABLE IF NOT EXISTS sites (\n  slug TEXT PRIMARY KEY,         -- home / 任意スラッグ\n  title TEXT NOT NULL,\n  body TEXT,                     -- 本文（HTML。管理者入力＝信頼）\n  published INTEGER NOT NULL DEFAULT 0,\n  show_join INTEGER NOT NULL DEFAULT 0, -- 会員申込フォームを表示（会員管理と連動）\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\n";
const m0012 = "-- 外部資料インポート（Notion / Googleドライブ）。既定はメタのみ。R2有効時のみ実ファイルを取り込む。\nCREATE TABLE IF NOT EXISTS imported_items (\n  id TEXT PRIMARY KEY,\n  source TEXT NOT NULL,      -- drive / notion\n  ext_id TEXT,              -- 元のID\n  title TEXT NOT NULL,\n  mime TEXT,\n  size INTEGER,\n  url TEXT,\n  file_id TEXT,             -- R2取り込み時の files.id（メタのみなら NULL）\n  imported_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_imported_source ON imported_items (source);\n";
const m0013 = "-- 外部アプリ：レジストリから署名検証して取り込んだアプリ（ランタイム型・データ）。\nCREATE TABLE IF NOT EXISTS external_apps (\n  id TEXT PRIMARY KEY,\n  name TEXT NOT NULL,\n  version TEXT NOT NULL,\n  category TEXT,\n  description TEXT,\n  permissions TEXT,      -- JSON配列\n  definition TEXT,       -- 宣言的アプリ定義（JSON）\n  installed_at INTEGER NOT NULL\n);\n\n-- アプリのドラフト：チャットでAI生成→管理者がレビュー→ホストへ公開申請。\nCREATE TABLE IF NOT EXISTS app_drafts (\n  id TEXT PRIMARY KEY,\n  name TEXT NOT NULL,\n  version TEXT NOT NULL DEFAULT '0.1.0',\n  category TEXT,\n  description TEXT,\n  permissions TEXT,      -- JSON配列（要求権限・レビュー対象）\n  definition TEXT,       -- 宣言的アプリ定義（JSON）\n  status TEXT NOT NULL DEFAULT 'pending', -- pending / submitted / rejected\n  created_by TEXT,\n  created_at INTEGER NOT NULL\n);\n";
const m0014 = "-- アプリ開発の企画・仕様＋事前4確認（環境/権限/安全/コスト）をドラフトに保持。\nALTER TABLE app_drafts ADD COLUMN spec TEXT;                 -- 企画・仕様\nALTER TABLE app_drafts ADD COLUMN est_tokens INTEGER;       -- 推定消費トークン/実行\nALTER TABLE app_drafts ADD COLUMN preflight TEXT;           -- 事前確認結果（JSON: {ok, checks[]}）\nALTER TABLE app_drafts ADD COLUMN gate_status TEXT NOT NULL DEFAULT 'planning'; -- planning / ready / blocked\n";
const m0015 = "-- AIチャットのセッションと履歴（セッション切替・モデル選択用）。\nCREATE TABLE IF NOT EXISTS chat_sessions (\n  id TEXT PRIMARY KEY,\n  owner TEXT NOT NULL,          -- session.uid 等（個人スコープ）\n  title TEXT,\n  model TEXT,                   -- gemini / claude / local（既定はエンジン設定）\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_chat_sessions_owner ON chat_sessions (owner, updated_at);\n\nCREATE TABLE IF NOT EXISTS chat_messages (\n  id TEXT PRIMARY KEY,\n  session_id TEXT NOT NULL,\n  role TEXT NOT NULL,           -- user / assistant\n  content TEXT NOT NULL,\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_chat_messages_session ON chat_messages (session_id, created_at);\n";
const m0016 = "-- マルチエージェントの長時間ジョブ（バックグラウンド実行）。drain で順次処理。\nCREATE TABLE IF NOT EXISTS agent_jobs (\n  id TEXT PRIMARY KEY,\n  owner TEXT NOT NULL,\n  session_id TEXT,\n  prompt TEXT NOT NULL,\n  role TEXT NOT NULL DEFAULT 'member',\n  status TEXT NOT NULL DEFAULT 'pending',\n  result TEXT,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_agent_jobs_status ON agent_jobs (status, created_at);\n";
const m0017 = "-- A2A 公開アクション（ノーコード宣言型＋アプリアクション参照）を一元管理。read専用・スコープ付き。\nCREATE TABLE IF NOT EXISTS a2a_actions (\n  id TEXT PRIMARY KEY,\n  name TEXT NOT NULL,            -- 公開名（相手が呼ぶ名前）\n  kind TEXT NOT NULL,           -- 'app'（Part.actions参照） / 'decl'（ノーコード宣言）\n  spec TEXT NOT NULL,           -- JSON: app={appId,action} / decl={type,config}\n  scope TEXT NOT NULL DEFAULT 'common', -- common / conn / group\n  target TEXT NOT NULL DEFAULT '',       -- conn=相手license / group=groupId / common=空\n  enabled INTEGER NOT NULL DEFAULT 1,\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_a2a_actions_name ON a2a_actions (name);\n";
const m0018 = "-- クライアント→ホストへの報告（自動エラー・不具合/要望リクエスト）の送信アウトボックス。\n-- オフライン/一時障害でも貯めておき、cron/drain で未送信分をまとめてホストへ送る。\nCREATE TABLE IF NOT EXISTS client_report_outbox (\n  id TEXT PRIMARY KEY,\n  kind TEXT NOT NULL,\n  severity TEXT,\n  category TEXT,\n  title TEXT,\n  message TEXT NOT NULL,\n  context TEXT,\n  fingerprint TEXT,\n  sent INTEGER NOT NULL DEFAULT 0,\n  attempts INTEGER NOT NULL DEFAULT 0,\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_outbox_sent ON client_report_outbox (sent, created_at);\n\n-- ホストからの対応返信（resolved/wontfix）。利用者へ「対応済み」を表示するため保持。\nCREATE TABLE IF NOT EXISTS host_report_replies (\n  id TEXT PRIMARY KEY,\n  kind TEXT,\n  title TEXT,\n  status TEXT,\n  resolution TEXT,\n  pr_url TEXT,\n  seen INTEGER NOT NULL DEFAULT 0,\n  received_at INTEGER NOT NULL\n);\n";
const m0019 = "-- Google Meet 会議記録の要約キャッシュ（方式③：会議後トランスクリプト→Claude要約→knowledge/reminders へ反映）。\n-- Calendar / Gmail は道具経由のオンデマンド取得で十分なため、ローカルテーブルは持たない（Meet のみキャッシュ）。\nCREATE TABLE IF NOT EXISTS meet_records (\n  id TEXT PRIMARY KEY,                          -- Meet conferenceRecord 名（conferenceRecords/xxx）\n  space_name TEXT,                              -- spaces/xxx\n  title TEXT,                                   -- 会議タイトル\n  start_time TEXT,                              -- ISO（会議開始）\n  end_time TEXT,                                -- ISO（会議終了）\n  summary TEXT,                                 -- Claude による議事録要約\n  actions TEXT,                                 -- 抽出したアクションアイテム（JSON配列）\n  knowledge_saved INTEGER NOT NULL DEFAULT 0,   -- ナレッジ保存済みフラグ（二重保存防止）\n  reminders_saved INTEGER NOT NULL DEFAULT 0,   -- リマインダ登録済みフラグ\n  owner TEXT,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_meet_records_created ON meet_records (created_at);\n";
const m0020 = `-- 請求書管理：画像/PDFから抽出した請求情報＋支払いステータス。元ファイルは files テーブル（R2/KV）へ保存し file_id で参照。
-- 抽出は Claude マルチモーダル（lib/media-ai.ts extractInvoiceData）。期日接近の未払は reminders へ通知予約。
CREATE TABLE IF NOT EXISTS invoices (
  id TEXT PRIMARY KEY,
  owner TEXT NOT NULL,                   -- 登録者/組織スコープ（自動取込は "org"）
  file_id TEXT,                          -- files テーブルの元ファイル参照（PDF/画像）
  vendor TEXT,                           -- 請求元
  amount INTEGER,                        -- 金額（円・整数）
  issued_date TEXT,                      -- 発行日（ISO日付）
  due_date TEXT,                         -- 支払期日（ISO日付）
  status TEXT NOT NULL DEFAULT 'unpaid', -- unpaid / paid / overdue / canceled
  notes TEXT,
  source TEXT,                           -- mail / manual / chat（入力経路）
  created_at INTEGER NOT NULL,
  updated_at INTEGER NOT NULL,
  deleted_at INTEGER
);
CREATE INDEX IF NOT EXISTS idx_invoices_status ON invoices (status, due_date);
CREATE INDEX IF NOT EXISTS idx_invoices_owner ON invoices (owner, created_at);
`;
const m0021 = '-- アプリ内通知：自動取込(owner="org")など LINE 未紐付けスコープ向けの期日通知等を保持。\n-- drain（cron）が積み、UI（ヘッダのベル＋/api/notifications）が表示・既読化する。\nCREATE TABLE IF NOT EXISTS notifications (\n  id TEXT PRIMARY KEY,\n  owner TEXT NOT NULL,         -- 通知先スコープ（"org" / "line:<id>" / session uid）\n  kind TEXT NOT NULL,          -- 種別（reminder 等）\n  body TEXT NOT NULL,          -- 本文\n  link TEXT,                   -- 任意の遷移先（例 /invoices）\n  read_at INTEGER,             -- 既読時刻（NULL=未読）\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_notifications_owner ON notifications (owner, read_at, created_at);\n';
const m0022 = "-- API使用量に token / 推定費用 / 単位 を追加（第三者レビュー P0-2）。\n-- 回数(count)だけでは実費とズレるため、provider別の input/output token と推定USDを日次で蓄積する。\n-- units = token以外の従量単位（Web検索回数・音声/動画秒数など）。\nALTER TABLE api_usage ADD COLUMN input_tokens INTEGER NOT NULL DEFAULT 0;\nALTER TABLE api_usage ADD COLUMN output_tokens INTEGER NOT NULL DEFAULT 0;\nALTER TABLE api_usage ADD COLUMN est_usd REAL NOT NULL DEFAULT 0;\nALTER TABLE api_usage ADD COLUMN units INTEGER NOT NULL DEFAULT 0;\n";
const m0023 = "-- ファイル保存時暗号化と保持期限（第三者レビュー P0-5）。\n-- enc=1 は本体が MASTER_KEY 由来鍵で AES-GCM 暗号化済み（既存=0 は平文・後方互換）。\n-- expires_at（UTC秒）を過ぎたファイルは削除ジョブが物理削除する。\nALTER TABLE files ADD COLUMN enc INTEGER NOT NULL DEFAULT 0;\nALTER TABLE files ADD COLUMN expires_at INTEGER;\nCREATE INDEX IF NOT EXISTS idx_files_expires ON files (expires_at);\n";
const m0024 = "-- エージェントの破壊的/対外操作の人間承認キュー（第三者レビュー P0-4）。\n-- メール送信・予定改変/削除・A2A連携など「対外/破壊系」ツールは、実行前に preview を出して\n-- pending で保留し、人間が承認したときだけ実行する（操作プレビュー→承認→実行）。\nCREATE TABLE IF NOT EXISTS agent_approvals (\n  id TEXT PRIMARY KEY,\n  owner TEXT NOT NULL,            -- 起案スコープ（line:<id> / session uid 等）\n  tool TEXT NOT NULL,            -- 対象ツール名\n  args TEXT NOT NULL,            -- 引数(JSON)\n  preview TEXT NOT NULL,         -- 人間向けの操作プレビュー\n  status TEXT NOT NULL DEFAULT 'pending', -- pending / approved / rejected\n  result TEXT,                  -- 承認実行後の結果\n  created_at INTEGER NOT NULL,\n  decided_at INTEGER,\n  decided_by TEXT\n);\nCREATE INDEX IF NOT EXISTS idx_approvals_pending ON agent_approvals (status, created_at);\n";
const m0025 = "-- P0-1（IDOR是正）：ファイルにアクセス文脈(ctx)を付与し、所有者/ロール検査の土台にする。\n-- org=組織共有プール（org文脈ユーザーが共有）／personal=個人(LINE/Discord等)の私的ファイル。\n-- 既存行は歴史的に組織内共有前提だったため 'org' へ backfill（NULL も scoped クエリ側で org 扱い）。\nALTER TABLE files ADD COLUMN ctx TEXT;\nUPDATE files SET ctx = 'org' WHERE ctx IS NULL;\nCREATE INDEX IF NOT EXISTS idx_files_owner ON files (created_by, deleted_at);\n";
const m0026 = "-- 会員（ログインユーザー）の脱退申請。本人が退会を申請し、管理者が承認して無効化する。\n-- 業務データは団体に帰属するため削除しない（アカウントの無効化のみ）。NULL=申請なし。\nALTER TABLE users ADD COLUMN leave_requested_at INTEGER;\n";
const m0027 = "-- パフォーマンス用インデックス（DDL限定）。\n-- 当月収支は date の範囲検索（>= 月初 AND < 翌月初）で使うため date 単体インデックスで range scan を効かせる。\nCREATE INDEX IF NOT EXISTS idx_tx_date ON transactions (date);\n-- 承認待ち（個人→組織）：share_scope='org' AND review_status='pending' ORDER BY created_at。\nCREATE INDEX IF NOT EXISTS idx_personal_share_review ON personal_items (share_scope, review_status, created_at);\n";
const m0028 = "-- 運用クォータの自己カウント（KV書き込み等）。CFは実行時にKV書込回数を出さないため自前で日次集計する。\n-- api_usage（AI/API回数）とは別テーブル＝AI使用量の集計を汚さない。op=種別（例 kv_write）、day=UTC日付。\nCREATE TABLE IF NOT EXISTS op_usage (\n  op    TEXT NOT NULL,\n  day   TEXT NOT NULL,\n  count INTEGER NOT NULL DEFAULT 0,\n  PRIMARY KEY (op, day)\n);\n";
const m0029 = "-- 会計拡張の土台：勘定科目マスタ・複式仕訳・固定資産/減価償却・レジ締め・外部連携の重複防止。\n-- 既存の単式（transactions/categories/wallets）は壊さず、勘定科目を後付けする（account_item_id を ALTER）。\n-- 既定勘定科目の投入はアプリ層で冪等に行う（DDL限定の規約・ensureChartOfAccounts）。\n\n-- 勘定科目マスタ。major=資産/負債/純資産/収益/費用、normal_balance=借方/貸方。\nCREATE TABLE IF NOT EXISTS account_items (\n  id TEXT PRIMARY KEY,\n  code TEXT NOT NULL,\n  name TEXT NOT NULL,\n  major TEXT NOT NULL,\n  normal_balance TEXT NOT NULL,\n  summary_group TEXT,\n  freee_account_item_id TEXT,\n  builtin INTEGER NOT NULL DEFAULT 0,\n  enabled INTEGER NOT NULL DEFAULT 1,\n  sort_order INTEGER NOT NULL DEFAULT 0\n);\nCREATE UNIQUE INDEX IF NOT EXISTS idx_account_items_code ON account_items (code);\n\n-- 既存の科目・口座に勘定科目を紐付け（橋渡しで借方/貸方科目を解決）。\nALTER TABLE categories ADD COLUMN account_item_id TEXT;\nALTER TABLE wallets ADD COLUMN account_item_id TEXT;\n-- 取引に勘定科目を直付け（経費のAI勘定科目選択用。未設定なら category 経由で解決）。\nALTER TABLE transactions ADD COLUMN account_item_id TEXT;\n\n-- 複式仕訳。単式取引は橋渡しで都度仕訳化するため、ここには手動仕訳・減価償却・レジ締め差異のみ保存。\nCREATE TABLE IF NOT EXISTS journal_entries (\n  id TEXT PRIMARY KEY,\n  fiscal_period_id TEXT NOT NULL,\n  date TEXT NOT NULL,\n  description TEXT,\n  source TEXT NOT NULL DEFAULT 'manual',\n  source_ref TEXT,\n  created_by TEXT,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL,\n  deleted_at INTEGER\n);\nCREATE INDEX IF NOT EXISTS idx_je_period ON journal_entries (fiscal_period_id, date);\nCREATE INDEX IF NOT EXISTS idx_je_source ON journal_entries (source, source_ref);\nCREATE TABLE IF NOT EXISTS journal_lines (\n  id TEXT PRIMARY KEY,\n  entry_id TEXT NOT NULL,\n  side TEXT NOT NULL,\n  account_item_id TEXT NOT NULL,\n  amount INTEGER NOT NULL,\n  memo TEXT,\n  sort_order INTEGER NOT NULL DEFAULT 0\n);\nCREATE INDEX IF NOT EXISTS idx_jl_entry ON journal_lines (entry_id);\n\n-- 固定資産と減価償却。\nCREATE TABLE IF NOT EXISTS fixed_assets (\n  id TEXT PRIMARY KEY,\n  name TEXT NOT NULL,\n  acquired_date TEXT NOT NULL,\n  acquisition_cost INTEGER NOT NULL,\n  useful_life_years INTEGER NOT NULL,\n  method TEXT NOT NULL,\n  residual_value INTEGER NOT NULL DEFAULT 0,\n  rate REAL,\n  asset_account_item_id TEXT,\n  expense_account_item_id TEXT,\n  fiscal_period_id TEXT,\n  status TEXT NOT NULL DEFAULT 'active',\n  notes TEXT,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL,\n  deleted_at INTEGER\n);\nCREATE TABLE IF NOT EXISTS depreciation_entries (\n  id TEXT PRIMARY KEY,\n  asset_id TEXT NOT NULL,\n  fiscal_period_id TEXT NOT NULL,\n  period_label TEXT NOT NULL,\n  amount INTEGER NOT NULL,\n  journal_entry_id TEXT,\n  created_at INTEGER NOT NULL\n);\nCREATE UNIQUE INDEX IF NOT EXISTS idx_dep_unique ON depreciation_entries (asset_id, period_label);\n\n-- レジ締め（日次/月次/年度末）。想定額 vs 実査額・差異・AI原因推定。\nCREATE TABLE IF NOT EXISTS register_closures (\n  id TEXT PRIMARY KEY,\n  fiscal_period_id TEXT NOT NULL,\n  wallet_id TEXT NOT NULL,\n  kind TEXT NOT NULL,\n  period_label TEXT NOT NULL,\n  expected_amount INTEGER NOT NULL,\n  counted_amount INTEGER NOT NULL,\n  difference INTEGER NOT NULL,\n  ai_reason TEXT,\n  adjustment_entry_id TEXT,\n  closed_by TEXT,\n  closed_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_closure ON register_closures (wallet_id, kind, period_label);\n\n-- 外部連携（Square/freee）の取込重複防止。今回はDDLのみ（取込コードは後続）。\nCREATE TABLE IF NOT EXISTS external_sync (\n  id TEXT PRIMARY KEY,\n  source TEXT NOT NULL,\n  external_id TEXT NOT NULL,\n  local_id TEXT,\n  local_kind TEXT,\n  imported_at INTEGER NOT NULL\n);\nCREATE UNIQUE INDEX IF NOT EXISTS idx_external_sync ON external_sync (source, external_id);\n";
const m0030 = "-- 招待なし公開A2A：受付箱（問い合わせ/接続申請）とブロック名簿。\n-- 受付ポリシー（box/auto/hybrid＋信頼閾値）は KV settings(reception_policy) に格納。\n-- 公開アクションは a2a_actions.scope='public'（DDL変更不要・値追加のみ）。\nCREATE TABLE IF NOT EXISTS a2a_inquiries (\n  id           TEXT PRIMARY KEY,\n  from_license TEXT NOT NULL,        -- 送信元（ホスト署名で実在保証済み）\n  from_name    TEXT,\n  action       TEXT,                 -- 要求された公開アクション名（接続申請は 'connect'）\n  args         TEXT,                 -- JSON\n  message      TEXT,\n  trust        TEXT,                 -- JSON: {hostTrust} 受信時に同梱された相手評価\n  status       TEXT NOT NULL DEFAULT 'pending', -- pending/approved/rejected/blocked\n  created_at   INTEGER NOT NULL,\n  decided_at   INTEGER\n);\nCREATE INDEX IF NOT EXISTS idx_inq_status ON a2a_inquiries (status, created_at);\n\nCREATE TABLE IF NOT EXISTS a2a_blocks (\n  from_license TEXT PRIMARY KEY,\n  reason       TEXT,\n  created_at   INTEGER NOT NULL\n);\n";
const m0031 = "-- 名簿に会費金額・ランク（区分）・会計連携用の取引IDを追加。\n-- fee_amount: 会費の金額（円）。fee_status が paid になったとき会計へ自動計上する。\n-- rank: 会員ランク/区分（正会員・賛助会員 等の自由記述）。\n-- fee_tx_id: 自動計上した会計取引のID（二重計上防止＋paid解除時の取り消しに使う）。\nALTER TABLE membership ADD COLUMN fee_amount INTEGER;\nALTER TABLE membership ADD COLUMN rank TEXT;\nALTER TABLE membership ADD COLUMN fee_tx_id TEXT;\n";
const m0032 = "-- 予定とGoogleカレンダーの双方向同期用。\n-- google_event_id: 対応する Google カレンダーのイベントID（内部行とGoogle側を1:1で対応付け、\n--   取り込み時の重複防止・更新/削除の伝播に使う）。\n-- google_synced_at: 最後にGoogleと同期した時刻（取込/プッシュの目安）。\nALTER TABLE schedules ADD COLUMN google_event_id TEXT;\nALTER TABLE schedules ADD COLUMN google_synced_at INTEGER;\nCREATE INDEX IF NOT EXISTS idx_sched_gid ON schedules (google_event_id);\n";
const m0033 = "-- イベント（公開申込・参加者管理）。HP/LP 公開（sites）と会員管理・会計に連動。\n-- events.plans は JSON 配列 [{id,name,price}]（参加プラン）。capacity=NULL は定員無制限。\nCREATE TABLE IF NOT EXISTS events (\n  id TEXT PRIMARY KEY,\n  slug TEXT NOT NULL UNIQUE,\n  title TEXT NOT NULL,\n  lead TEXT,\n  body TEXT,\n  location TEXT,\n  event_date TEXT,\n  capacity INTEGER,\n  plans TEXT,\n  published INTEGER NOT NULL DEFAULT 0,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\n\n-- イベント参加登録。user_id=作成したログインアカウント、member_id=名簿(membership)行。\n-- pay_status: unpaid / paid（デモ決済で paid）。fee_tx_id=参加費入金の会計取引（二重計上防止）。\nCREATE TABLE IF NOT EXISTS event_registrations (\n  id TEXT PRIMARY KEY,\n  event_id TEXT NOT NULL,\n  user_id TEXT,\n  member_id TEXT,\n  name TEXT NOT NULL,\n  contact TEXT,\n  plan_id TEXT,\n  plan_name TEXT,\n  headcount INTEGER NOT NULL DEFAULT 1,\n  amount INTEGER,\n  pay_status TEXT NOT NULL DEFAULT 'unpaid',\n  fee_tx_id TEXT,\n  paid_at INTEGER,\n  created_at INTEGER NOT NULL\n);\n\nCREATE INDEX IF NOT EXISTS idx_event_regs_event ON event_registrations (event_id, created_at);\nCREATE INDEX IF NOT EXISTS idx_event_regs_user ON event_registrations (user_id);\n";
const m0034 = "-- イベントのカバー画像URL（任意）。公開ページのヒーロー/一覧サムネに使用。team/団体ごとに自由設定。\nALTER TABLE events ADD COLUMN image TEXT;\n";
const m0035 = "-- ページビルダー：ブロック構成の保存。layout=公開版、layout_draft=編集中（下書き）、seo=任意メタ。\n-- いずれも JSON 文字列。NULL の sites 行は従来どおり body(HTML) を描画（後方互換）。\nALTER TABLE sites ADD COLUMN layout TEXT;\nALTER TABLE sites ADD COLUMN layout_draft TEXT;\nALTER TABLE sites ADD COLUMN seo TEXT;\n";
const m0036 = "-- アプリのバージョン履歴（不変スナップショット）。更新/ロールバックは external_apps.active_version の切替で行う。\nCREATE TABLE IF NOT EXISTS app_versions (\n  app_id TEXT NOT NULL,\n  version TEXT NOT NULL,\n  definition TEXT,        -- その版の定義(JSON)\n  permissions TEXT,       -- その版の要求権限(JSON配列)\n  changelog TEXT,         -- AI生成の変更ログ\n  ai_meta TEXT,           -- 機械情報(model/tokens 等, JSON)\n  source TEXT NOT NULL DEFAULT 'local',  -- local / store\n  created_by TEXT,\n  created_at INTEGER NOT NULL,\n  PRIMARY KEY (app_id, version)\n);\n-- external_apps に現役版ポインタと導入元を追加（既存行は NULL=旧来動作）。\nALTER TABLE external_apps ADD COLUMN active_version TEXT;\nALTER TABLE external_apps ADD COLUMN source TEXT;\n-- 草案に AI変更ログ列を追加。\nALTER TABLE app_drafts ADD COLUMN changelog TEXT;\n";
const m0037 = "-- 定期実行タスク（スケジュールタスク）。owner の指示(prompt)を freq の周期で無人実行（agent_jobs へ enqueue）。\n-- 時刻は JST 基準の「0:00 からの分」(at_min)。weekly は dow(0=日..6=土)、monthly は dom(1..28)。\nCREATE TABLE IF NOT EXISTS scheduled_tasks (\n  id TEXT PRIMARY KEY,\n  owner TEXT NOT NULL,\n  prompt TEXT NOT NULL,\n  freq TEXT NOT NULL,                 -- 'daily' | 'weekly' | 'monthly'\n  at_min INTEGER NOT NULL DEFAULT 540, -- 実行時刻（JST・分）。既定 9:00\n  dow INTEGER,                        -- weekly のみ：0=日..6=土\n  dom INTEGER,                        -- monthly のみ：1..28\n  role TEXT NOT NULL DEFAULT 'member',\n  enabled INTEGER NOT NULL DEFAULT 1,\n  next_run INTEGER NOT NULL,          -- 次回実行 epoch秒\n  last_run INTEGER,\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_sched_tasks_due ON scheduled_tasks (enabled, next_run);\n";
const m0038 = "-- 宣言的アプリ（baku.app/1）の汎用データ保存先。CRUD型アプリ（記録・一覧・集計）が\n-- db.write/db.query で利用する。app_id でアプリ別、owner で利用者別にスコープする想定。\n-- data は任意の本文（JSON文字列やテキスト）。アプリは自分の app_id 行のみ読み書きする。\nCREATE TABLE IF NOT EXISTS app_records (\n  id TEXT PRIMARY KEY,\n  app_id TEXT NOT NULL,\n  owner TEXT NOT NULL,\n  data TEXT,\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_app_records_scope ON app_records (app_id, owner, created_at);\n";
const m0039 = "-- 段階実装（Phase制・再開可能）なアプリビルド。1実行=1ステップに抑え、短い実行枠でも確実に進む。\n-- status: planning（計画生成前）→ building（Phase 実装中）→ done / error。\n-- plan=JSON{ id,name,permissions,isCustomUI,phases:[{title,goal,kind,status}] }、definition=JSON（蓄積中の定義）。\n-- cursor=次に実装する Phase の index。paid=WorkersPaid（1実行で進めるステップ数の調整に使う）。\nCREATE TABLE IF NOT EXISTS app_builds (\n  id TEXT PRIMARY KEY,\n  owner TEXT NOT NULL,\n  session_id TEXT,\n  app_id TEXT,\n  name TEXT,\n  model TEXT,\n  paid INTEGER NOT NULL DEFAULT 0,\n  status TEXT NOT NULL DEFAULT 'planning',\n  spec TEXT,\n  plan TEXT,\n  definition TEXT,\n  cursor INTEGER NOT NULL DEFAULT 0,\n  attempts INTEGER NOT NULL DEFAULT 0,\n  error TEXT,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_app_builds_active ON app_builds(status, updated_at);\n";
const m0040 = "-- app_builds に kind を追加：'build'（新規作成・既定）と 'edit'（既存アプリの編集/デバッグ）。\n-- edit は app_id（対象）と spec（指示）を持ち、最小差分パッチで定義を更新→自動反映する（背景・再開可能）。\nALTER TABLE app_builds ADD COLUMN kind TEXT NOT NULL DEFAULT 'build';\n";
const m0041 = "-- 公開申請前のセルフチェック結果を草案に保持する。\n-- selfcheck=結果JSON（チェック項目・status・detail）、selfcheck_status='pass'|'fail'|NULL（未実施）。\n-- 申請は selfcheck_status='pass' のときのみ許可する（submitDraft のゲート）。\nALTER TABLE app_drafts ADD COLUMN selfcheck TEXT;\nALTER TABLE app_drafts ADD COLUMN selfcheck_status TEXT;\n";
const m0042 = "-- 拡張開発（フォーク）の許可スナップショットと来歴（クライアント側）。\n-- external_apps.allow_fork=導入時点で派生元が拡張開発を許可していたか（フォークボタン表示の判定用・最終検証は host）。\n-- forked_from_* は派生で作った草案/アプリが「どのアプリから派生したか」を必ず保持する（新アプリでも来歴が分かる）。\nALTER TABLE external_apps ADD COLUMN allow_fork INTEGER NOT NULL DEFAULT 0;\nALTER TABLE external_apps ADD COLUMN forked_from_id TEXT;\nALTER TABLE external_apps ADD COLUMN forked_from_name TEXT;\nALTER TABLE external_apps ADD COLUMN forked_from_version TEXT;\nALTER TABLE app_drafts ADD COLUMN forked_from_id TEXT;\nALTER TABLE app_drafts ADD COLUMN forked_from_name TEXT;\nALTER TABLE app_drafts ADD COLUMN forked_from_version TEXT;\n";
const m0043 = "-- フォーク元(上流)更新のAIマージ提案を一時保持する。\n-- merge_proposal=AIが生成した提案JSON（推奨可否・根拠・統合定義・上流版）。\n-- 提案を保存→ユーザー確認後に apply で適用（クライアントが定義を送り返さず、サーバ側の提案を正典にする＝改竄防止）。\nALTER TABLE app_drafts ADD COLUMN merge_proposal TEXT;\n";
const m0044 = "-- 公開ページ（ログイン不要・LP/申込フォーム）。AIがアプリ開発時に発行する /p/<slug>。\n-- アプリ(external_apps)に紐づき、表示HTML＋フォーム項目を持つ。匿名訪問者は閲覧と送信のみ可。\nCREATE TABLE IF NOT EXISTS public_pages (\n  slug TEXT PRIMARY KEY,\n  app_id TEXT NOT NULL,\n  title TEXT NOT NULL,\n  html TEXT NOT NULL,\n  fields TEXT NOT NULL DEFAULT '[]',\n  allow_files INTEGER NOT NULL DEFAULT 0,\n  enabled INTEGER NOT NULL DEFAULT 1,\n  created_by TEXT,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\n\n-- 公開フォーム送信（モデレーションキュー）。承認すると app_records へ取り込む（status=pending/approved/rejected）。\n-- 生IPは保存せず ip_hash（ハッシュ）のみ＝レート制限/不正調査用。\nCREATE TABLE IF NOT EXISTS public_submissions (\n  id TEXT PRIMARY KEY,\n  slug TEXT NOT NULL,\n  app_id TEXT NOT NULL,\n  data TEXT NOT NULL,\n  files TEXT,\n  ip_hash TEXT,\n  status TEXT NOT NULL DEFAULT 'pending',\n  created_at INTEGER NOT NULL,\n  reviewed_by TEXT,\n  reviewed_at INTEGER\n);\nCREATE INDEX IF NOT EXISTS idx_pubsub_scope ON public_submissions (slug, status, created_at);\n";
const m0045 = "-- 公開ページの送信時トリガ（B3）。送信を受けたら管理者へ通知し、任意で申込者へ確認メールを送る。\n-- email_field＝申込者メールが入るフォーム項目名（確認メール送信に使う）。\nALTER TABLE public_pages ADD COLUMN notify_admin INTEGER NOT NULL DEFAULT 1;\nALTER TABLE public_pages ADD COLUMN confirm_email INTEGER NOT NULL DEFAULT 0;\nALTER TABLE public_pages ADD COLUMN email_field TEXT;\nALTER TABLE public_pages ADD COLUMN confirm_subject TEXT;\nALTER TABLE public_pages ADD COLUMN confirm_body TEXT;\n";
const m0046 = "-- 公開フォームの決済（B4・有料申込/寄付/物販）。price>0 で Stripe Checkout に誘導する。\nALTER TABLE public_pages ADD COLUMN price INTEGER NOT NULL DEFAULT 0;     -- 金額（JPYは円・ゼロ小数）。0=無料。\nALTER TABLE public_pages ADD COLUMN currency TEXT NOT NULL DEFAULT 'jpy';\nALTER TABLE public_pages ADD COLUMN pay_label TEXT;                       -- 商品名/名目（未設定はタイトル）。\n\n-- 送信ごとの決済状態。none=無料／unpaid=要決済／paid=入金済。\nALTER TABLE public_submissions ADD COLUMN pay_status TEXT NOT NULL DEFAULT 'none';\nALTER TABLE public_submissions ADD COLUMN amount INTEGER;\nALTER TABLE public_submissions ADD COLUMN stripe_session TEXT;\n";
const m0047 = "-- アプリ内の複数エンティティ（型）対応（B7）。1つのアプリで顧客×案件のように複数の「テーブル」を持てる。\n-- collection で種別を分け、リレーションは data(JSON) に関連レコードの id を保持して結合する。\n-- NULL=従来どおり単一種別（後方互換）。\nALTER TABLE app_records ADD COLUMN collection TEXT;\nCREATE INDEX IF NOT EXISTS idx_app_records_collection ON app_records (app_id, collection, created_at);\n";
const m0048 = "-- Web Push 購読（B9・PWAプッシュ通知）。端末ごとの購読を owner に紐づけて保持する。\nCREATE TABLE IF NOT EXISTS push_subscriptions (\n  id TEXT PRIMARY KEY,\n  owner TEXT NOT NULL,\n  endpoint TEXT NOT NULL UNIQUE,\n  p256dh TEXT,\n  auth TEXT,\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_push_owner ON push_subscriptions (owner);\n";
const m0049 = "-- 承認ワークフロー（B10）。レコードに状態を持たせ、申請→承認→却下などの遷移を可能にする。\n-- NULL=状態管理なし（後方互換）。アプリは status で絞り込み、record.status op で遷移させる。\nALTER TABLE app_records ADD COLUMN status TEXT;\nCREATE INDEX IF NOT EXISTS idx_app_records_status ON app_records (app_id, status, created_at);\n";
const m0050 = '-- アプリのデータ変更監査（B11）。アプリ実行時の書込・削除・状態遷移を記録する。\n-- WHY app_audit_log: 別系統のレガシー監査 audit_log（0001_client.sql・actor/action/target）と名前が衝突し、\n-- 旧 audit_log には app_id 列が無いため index 作成が "no such column: app_id" で失敗していた（0050 以降が全停止）。\n-- アプリ実行監査は app_audit_log として分離する（旧 audit_log はファイル操作監査で引き続き使用）。\nCREATE TABLE IF NOT EXISTS app_audit_log (\n  id TEXT PRIMARY KEY,\n  app_id TEXT NOT NULL,\n  owner TEXT NOT NULL,          -- 実行者\n  op TEXT NOT NULL,             -- db.write / db.delete / record.status\n  detail TEXT,                  -- 要約（テーブル名・id・遷移先など。本文は保存しない）\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_app_audit_app ON app_audit_log (app_id, created_at);\n';
const m0051 = "-- お知らせ/ブログ（H2）。公開記事。body は本文（プレーンテキスト＝表示時は pre-wrap で安全描画）。\nCREATE TABLE IF NOT EXISTS posts (\n  id TEXT PRIMARY KEY,\n  slug TEXT NOT NULL UNIQUE,\n  title TEXT NOT NULL,\n  body TEXT,\n  published INTEGER NOT NULL DEFAULT 0,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_posts_pub ON posts (published, created_at);\n";
const m0052 = "-- 問い合わせ（H3）。サイトの問い合わせフォームblockからの受信箱。匿名受付・管理者が確認。\nCREATE TABLE IF NOT EXISTS contact_messages (\n  id TEXT PRIMARY KEY,\n  name TEXT,\n  email TEXT,\n  message TEXT NOT NULL,\n  page TEXT,\n  status TEXT NOT NULL DEFAULT 'new',\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_contact_created ON contact_messages (created_at);\n";
const m0053 = "-- アクセス解析（H5・内蔵カウンタ）。外部スクリプト不要・プライバシー配慮（個人を記録しない）。\n-- 日付×パスごとの閲覧数のみ集計する。\nCREATE TABLE IF NOT EXISTS pageviews (\n  day TEXT NOT NULL,\n  path TEXT NOT NULL,\n  count INTEGER NOT NULL DEFAULT 0,\n  PRIMARY KEY (day, path)\n);\n";
const m0054 = "-- 限定公開（H7）。サイト(LP)にパスワードを設定すると、閲覧前に入力ゲートを出す。\n-- password は SHA-256 hex（平文は保存しない）。NULL=誰でも閲覧可。\nALTER TABLE sites ADD COLUMN password TEXT;\n";
const m0055 = "-- アプリのAPI/Webhook公開（C4）。アプリごとのアクセストークン（外部システム連携・inbound webhook）。\n-- token_hash は SHA-256 hex（平文は保存しない）。\nCREATE TABLE IF NOT EXISTS api_tokens (\n  id TEXT PRIMARY KEY,\n  token_hash TEXT NOT NULL UNIQUE,\n  app_id TEXT NOT NULL,\n  owner TEXT NOT NULL,\n  label TEXT,\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_api_tokens_app ON api_tokens (app_id);\n";
const m0056 = "-- チャットメッセージに付随するアクションボタン（生成アプリの導線・会話の選択肢など）。\n-- JSON 配列（ChatAction[]）。NULL=ボタンなし（後方互換）。履歴復元時もボタンを再描画する。\nALTER TABLE chat_messages ADD COLUMN actions TEXT;\n";
const m0057 = "-- アプリの分類（category・既存）に加えてタグ（自由ラベル・複数）を持たせる。\n-- 一覧をジャンル/タグで絞り込めるようにする。JSON 配列（string[]）。NULL=タグ無し（後方互換）。\nALTER TABLE app_drafts ADD COLUMN tags TEXT;\nALTER TABLE external_apps ADD COLUMN tags TEXT;\n";
const m0058 = "-- 公開フォーム送信時の登録方式。'none'＝フォーム送信のみ（既定・後方互換）／\n-- 'guest'＝送信者を名簿にゲストとして登録する。クライアントが公開ページごとに選べる。\nALTER TABLE public_pages ADD COLUMN register_mode TEXT NOT NULL DEFAULT 'none';\n";
const m0059 = '-- アプリごとのアクセス権限（ロール）。管理者が「このアプリを使えるロール」を設定する。\n-- JSON 配列（例 ["accounting","clerical"]）。NULL/空＝全ロール可（既定・後方互換）。\n-- admin/developer は設定に関わらず常に利用可（管理・開発のため）。guest は対象外。\nALTER TABLE external_apps ADD COLUMN allowed_roles TEXT;\n';
