const m0061 = '-- 外部メッセージのコネクタ設定（§通信境界・egress 統制）。\n-- 論理チャンネル(label)→ プロバイダ(connector)＋宛先(address) の対応をデータで保持する。\n-- プロバイダ切替は connector/address の UPDATE 1 行で済む＝ベンダーロックイン回避。\nCREATE TABLE IF NOT EXISTS connectors (\n  id TEXT PRIMARY KEY,\n  label TEXT NOT NULL,\n  connector TEXT NOT NULL,        -- "discord" | "line" | "slack" ...（解釈はアダプタ）\n  address TEXT NOT NULL,          -- 宛先（webhook id / channel id 等）\n  enabled INTEGER NOT NULL DEFAULT 1,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_connectors_enabled ON connectors (enabled);\n';
const m0062 = "-- 外部送信(egress)の監査ログ（§通信境界・egress 統制）。EgressGateway を通った送信のうち\n-- 拒否（allowlist 違反）・失敗（HTTPエラー/例外）を記録する。量を抑え成功は記録しない。\n-- app_audit_log（アプリ実行）/ audit_log（ファイル操作）とは別系統＝egress 専用。\nCREATE TABLE IF NOT EXISTS egress_log (\n  id TEXT PRIMARY KEY,\n  connector TEXT NOT NULL,\n  host TEXT,\n  method TEXT,\n  ok INTEGER NOT NULL,\n  status INTEGER,\n  blocked INTEGER NOT NULL DEFAULT 0,   -- 1=allowlist 拒否で送信していない\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_egress_log_created ON egress_log (created_at);\n";
const m0063 = "-- 公開申込フォームでの個人情報取扱い同意の記録（P0-07）。\n-- consent_version: 同意した文面の版（後で文面を改訂したら版を上げて区別する）。\n-- consent_at: 同意した日時（epoch秒）。どちらも公開フォーム経由の申込でのみ設定される。\nALTER TABLE membership ADD COLUMN consent_version TEXT;\nALTER TABLE membership ADD COLUMN consent_at INTEGER;\n";
const m0064 = "-- HP/LP 公開履歴（P1-22）。公開（layout_draft→layout 反映）のたびに公開時点の layout を版として記録し、\n-- 以前の版へロールバックできるようにする。DDL 限定（スナップショット投入はアプリ層で冪等に＝publishLayout）。\nCREATE TABLE IF NOT EXISTS site_layout_versions (\n  id TEXT PRIMARY KEY,\n  slug TEXT NOT NULL,\n  version_no INTEGER NOT NULL,     -- slug 内の連番（1,2,3…）\n  layout TEXT NOT NULL,            -- 公開時点の layout JSON\n  published_by TEXT,               -- 公開した管理者 uid\n  published_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_slv_slug ON site_layout_versions (slug, version_no);\n";
const m0065 = "-- P0-01: 承認の権限昇格を塞ぐ。承認待ちに「起案者の権限コンテキスト」と「対象アプリ版」を保存し、\n-- 承認後の実行は承認者(admin)ではなく申請者ロールで再実行する（承認は「実行を許可する判断」だけに使う）。\n-- requester_role/ctx＝起案時の権限主体、app_id/screen_id＝対象、app_version＝申請後の定義変更検知用。\n-- error＝実行失敗の理由（P1-01：失敗を approved と記録しないため status を executing/failed に分離する）。\nALTER TABLE agent_approvals ADD COLUMN requester_role TEXT;\nALTER TABLE agent_approvals ADD COLUMN requester_ctx TEXT;\nALTER TABLE agent_approvals ADD COLUMN app_id TEXT;\nALTER TABLE agent_approvals ADD COLUMN screen_id TEXT;\nALTER TABLE agent_approvals ADD COLUMN app_version TEXT;\nALTER TABLE agent_approvals ADD COLUMN error TEXT;\n";
const m0066 = "-- P0-01: 承認対象の定義差し替え(TOCTOU)を塞ぐ。承認待ちに「対象種別」と「申請時に確認した\n-- 定義・権限の正規化ハッシュ」を保存し、承認実行時に現行定義の再ハッシュと完全一致したときだけ実行する。\n-- subject_type: installed / draft / outward。def_hash/perms_hash: 正規化JSON(キー順安定)のSHA-256(hex)。\n-- 旧レコード（NULL）は従来の app_version 比較にフォールバックする（後方互換）。\nALTER TABLE agent_approvals ADD COLUMN subject_type TEXT;\nALTER TABLE agent_approvals ADD COLUMN def_hash TEXT;\nALTER TABLE agent_approvals ADD COLUMN perms_hash TEXT;\n";
const m0067 = "-- 横断記憶（セッションを跨いで「覚えておく」personal な重要事項）。\n-- AIチャットが過去の会話で得た恒久的な好み・事実を保存し、新しいセッションでも想起できるようにする。\n-- owner スコープ（各自の記憶）。DDL のみ（データ投入はアプリ層で冪等に行う）。\nCREATE TABLE IF NOT EXISTS user_memory (\n  id TEXT PRIMARY KEY,\n  owner TEXT NOT NULL,\n  content TEXT NOT NULL,\n  source_session TEXT,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_user_memory_owner ON user_memory(owner, updated_at);\n";
const m0068 = "-- 公開フォームの承認フロー設定と取り込み先コレクション。\n-- auto_approve=1（既定）＝承認不要：送信を即アプリデータ(app_records)化し管理ビューにすぐ出す。0＝承認制。\n-- collection＝取り込み先（アプリの保存先 data.create の collection と一致させ、管理ビューの data.list と整合させる）。\nALTER TABLE public_pages ADD COLUMN auto_approve INTEGER NOT NULL DEFAULT 1;\nALTER TABLE public_pages ADD COLUMN collection TEXT;\n";
const m0069 = "-- プロジェクト：アカウント共有の第一級コンテナ（事業/イベント単位でアプリ＋公開LPをまとめる）。\nCREATE TABLE IF NOT EXISTS projects (\n  id TEXT PRIMARY KEY,\n  name TEXT NOT NULL,\n  description TEXT,\n  color TEXT,\n  icon TEXT,\n  archived INTEGER NOT NULL DEFAULT 0,\n  created_by TEXT,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\n-- アプリの所属プロジェクト（0〜1）。LPはアプリの公開ページなので自動的に同じプロジェクトに属する。\nALTER TABLE external_apps ADD COLUMN project_id TEXT;\nCREATE INDEX IF NOT EXISTS idx_external_apps_project ON external_apps (project_id);\n";
const m0070 = "-- プロジェクト公開ハブ：配下の公開ページ(LP)をまとめた対外ページ /hub/<projectId>。既定OFF（誤公開防止）。\nALTER TABLE projects ADD COLUMN hub_enabled INTEGER NOT NULL DEFAULT 0;\nALTER TABLE projects ADD COLUMN hub_intro TEXT;\n";
const m0071 = "-- app_builds に stop_reason を追加：終了/打ち切りの理由を型として残し再開・運用判断を可能にする。\n-- 値の例: 'completed' / 'partial' / 'age'(時間切れ) / 'attempts'(再試行尽き) / 'no-plan'(プラン生成失敗) /\n--          'model-error'(LLM失敗) / 'validate'(検証失敗) / 'system'(内部例外) / 'nochange'(編集で変更なし)。\n-- status は TEXT のまま運用値 'done_partial'(失敗工程ありで完了) を追加で用いる（DDL変更不要）。\nALTER TABLE app_builds ADD COLUMN stop_reason TEXT;\n";
const m0072 = '-- 公開入口（フォーム送信・翻訳など）のアトミックなレート制限用テーブル。\n-- WHY: 従来は KV の get→put 加算で、同時リクエスト時に上限を超え得た（非アトミック）。\n--   D1 の "INSERT ... ON CONFLICT DO UPDATE SET count=count+1 RETURNING count" は単一文＝原子的に\n--   加算と現在値取得ができ、同時アクセスでも超過しない。bucket は IP×endpoint×時間窓のキー。\nCREATE TABLE IF NOT EXISTS rate_limits (\n  bucket TEXT NOT NULL,\n  window_start INTEGER NOT NULL,\n  count INTEGER NOT NULL DEFAULT 0,\n  PRIMARY KEY (bucket, window_start)\n);\n-- 期限切れ窓の掃除（window_start での範囲削除）を高速化。\nCREATE INDEX IF NOT EXISTS idx_rate_limits_window ON rate_limits(window_start);\n';
const m0073 = "-- N9（スマート公開フォーム）：公開フォームの定員＋キャンセル待ち。\n-- capacity=NULL は定員無制限（既定）。定員に達した後の送信は status='waitlist' で受け付け、管理者が承認で繰り上げる。\nALTER TABLE public_pages ADD COLUMN capacity INTEGER;\n";
const m0074 = "-- 素材ライブラリ（HP用の画像/SVGロゴ/動画）。実体は KV(media:<id>) または R2、メタはここで一覧/削除/再利用。\nCREATE TABLE IF NOT EXISTS media_assets (\n  id TEXT PRIMARY KEY,\n  name TEXT,\n  kind TEXT,                 -- image | svg | video\n  mime TEXT,\n  size INTEGER,\n  backend TEXT,              -- kv | r2\n  created_by TEXT,\n  created_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_media_assets_created ON media_assets(created_at DESC);\n";
const m0075 = "-- HP の AI 生成を背景Phase制で進めるジョブ表（アプリの app_builds と同型）。\n-- status: planning → building → done | error。plan=作るブロック型の配列、blocks=蓄積中の生成結果、cursor=進捗。\n-- lease（updated_at が一定時間更新されない active 行）は cron drain が回収して再開する。\nCREATE TABLE IF NOT EXISTS site_builds (\n  id TEXT PRIMARY KEY,\n  owner TEXT,\n  slug TEXT NOT NULL,\n  title TEXT,\n  status TEXT NOT NULL,\n  prompt TEXT,\n  base TEXT,\n  plan TEXT,\n  blocks TEXT,\n  cursor INTEGER DEFAULT 0,\n  attempts INTEGER DEFAULT 0,\n  model TEXT,\n  note TEXT,\n  error TEXT,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_site_builds_active ON site_builds(status, updated_at);\nCREATE INDEX IF NOT EXISTS idx_site_builds_slug ON site_builds(slug, created_at DESC);\n";
const m0076 = `-- メッセンジャー（LINE/Discord/Slack）でアップロードされたバイナリ（画像/動画/音声/PDF）の
-- 「即レス＋選択肢＋待機ウィンドウでまとめて背景処理」用キュー。
-- 同一 owner の status='queued' 行が1バッチ。idx＝バッチ内の通し番号（1枚目..）。
-- mode: null=未決（選択待ち）/ read / store / skip。deadline を過ぎ mode が決まれば cron が一括処理し結果をまとめて push。
CREATE TABLE IF NOT EXISTS upload_queue (
  id TEXT PRIMARY KEY,
  owner TEXT NOT NULL,        -- "connector:externalId"（push 宛先の解決にも使う）
  connector TEXT,
  role TEXT,                  -- 受信時の会員ロール（背景でのagent実行に使う）
  file_id TEXT NOT NULL,      -- 保存済みファイル（storage.files.id）
  name TEXT,
  mime TEXT,
  idx INTEGER NOT NULL,       -- バッチ内の通し番号
  mode TEXT,                  -- null=未決 / read / store / skip
  context TEXT,               -- 自然文指示の文脈（例「領収書」）
  status TEXT NOT NULL,       -- queued / processing / done / skipped / error
  result TEXT,
  deadline INTEGER NOT NULL,  -- この時刻を過ぎ mode が決まれば処理（連投をまとめる待機ウィンドウ）
  attempts INTEGER DEFAULT 0,
  created_at INTEGER NOT NULL,
  updated_at INTEGER NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_upload_queue_owner ON upload_queue(owner, status);
CREATE INDEX IF NOT EXISTS idx_upload_queue_ready ON upload_queue(status, deadline);
`;
const m0077 = "-- 既存メンバーへの外部連携コード（アカウントを増やさず、本人の既存アカウントへ LINE/Discord/Slack を紐付ける）。\n-- target_user_id が入った招待コードは「新規参加」ではなく「既存ユーザーへの identity 連携」として処理する。\nALTER TABLE invites ADD COLUMN target_user_id TEXT;\n";
