const m0079 = "-- AI API呼び出しの明細ログ（1呼び出し=1行）。プロンプト・本文は保存しない（トークン数とメタデータのみ）。\n-- 金額は焼き込まない：単価は変動するため、集計時に単価表（MODEL_PRICING）と掛けて算出する。\nCREATE TABLE IF NOT EXISTS ai_call_log (\n  id TEXT PRIMARY KEY,\n  ts INTEGER NOT NULL,\n  provider TEXT NOT NULL,\n  model TEXT,\n  feature TEXT NOT NULL DEFAULT 'other',\n  plan TEXT,\n  input_tokens INTEGER NOT NULL DEFAULT 0,\n  output_tokens INTEGER NOT NULL DEFAULT 0,\n  cache_read_tokens INTEGER NOT NULL DEFAULT 0,\n  cache_write_tokens INTEGER NOT NULL DEFAULT 0\n);\nCREATE INDEX IF NOT EXISTS idx_ai_call_log_ts ON ai_call_log(ts);\nCREATE INDEX IF NOT EXISTS idx_ai_call_log_feature_ts ON ai_call_log(feature, ts);\n";
const m0080 = "-- タスク実行ログ（実績＆成長ループ・1タスク=1行）。依頼本文・応答本文は保存しない\n-- （種別・完了/失敗・未対応要求の一行要約・フィードバックなどメタデータのみ）。\nCREATE TABLE IF NOT EXISTS task_logs (\n  id TEXT PRIMARY KEY,\n  ts INTEGER NOT NULL,\n  owner TEXT,\n  role TEXT,\n  source TEXT NOT NULL DEFAULT 'chat',\n  kind TEXT NOT NULL DEFAULT 'inquiry',\n  ai_completed INTEGER NOT NULL DEFAULT 0,\n  exec_type TEXT NOT NULL DEFAULT 'suggest',\n  rework INTEGER NOT NULL DEFAULT 0,\n  fail_reason TEXT,\n  unmet TEXT,\n  session_id TEXT,\n  message_id TEXT,\n  feedback TEXT,\n  saved_minutes INTEGER\n);\nCREATE INDEX IF NOT EXISTS idx_task_logs_ts ON task_logs(ts);\nCREATE INDEX IF NOT EXISTS idx_task_logs_session_ts ON task_logs(session_id, ts);\n";
const m0081 = "-- 簡易NPS（月1回・任意）「同僚に勧めたい？」yes/neutral/no。拡張シグナルとして実績レポートに載せる。\nCREATE TABLE IF NOT EXISTS nps_responses (\n  id TEXT PRIMARY KEY,\n  ts INTEGER NOT NULL,\n  owner TEXT,\n  score TEXT NOT NULL\n);\nCREATE INDEX IF NOT EXISTS idx_nps_ts ON nps_responses(ts);\n";
const m0082 = "-- 外部イベントトリガの基盤（DDLのみ）。生成アプリの triggers（messaging 受信 / Google の新規データ）を\n-- 起点に画面を自動実行するための実行履歴・重複防止・poll カーソルを保持する。\n-- ディスパッチ実体（受信割り込み / ポーリング）は後続フェーズ。このフェーズでは基盤テーブルのみ用意する。\n\n-- トリガ実行履歴。event_key で同一イベントの二重実行を防ぐ（app_id+trigger_id+event_key が一意）。\nCREATE TABLE IF NOT EXISTS app_event_runs (\n  id TEXT PRIMARY KEY,\n  app_id TEXT NOT NULL,\n  trigger_id TEXT NOT NULL,\n  source TEXT NOT NULL,\n  event_key TEXT NOT NULL,\n  status TEXT NOT NULL,\n  error TEXT,\n  created_at INTEGER NOT NULL,\n  updated_at INTEGER NOT NULL\n);\n\nCREATE UNIQUE INDEX IF NOT EXISTS idx_app_event_runs_unique\nON app_event_runs(app_id, trigger_id, event_key);\n\n-- ポーリング型トリガ（Gmail/Forms/Sheets/Drive/Calendar）の次回取得位置。\nCREATE TABLE IF NOT EXISTS app_event_cursors (\n  app_id TEXT NOT NULL,\n  trigger_id TEXT NOT NULL,\n  cursor TEXT,\n  updated_at INTEGER NOT NULL,\n  PRIMARY KEY(app_id, trigger_id)\n);\n";
const m0083 = "-- 0083_diag_build_id.sql — ビルド単位の生成過程トレース\n-- diagnostics に build_id を付与し、特定ビルド（app_builds.id）で全工程ログを引けるようにする。\n-- WHY: 従来 diagnostics は build_id を持たず全カテゴリ混在＝「どのビルドで何が起きたか」を後から復元できなかった。\nALTER TABLE diagnostics ADD COLUMN build_id TEXT;\nCREATE INDEX IF NOT EXISTS idx_diag_build ON diagnostics(build_id, created_at);\n";
